from llama_stack_client import LlamaStackAgent
import re

def detect_safety_false_positives(agent_logs):
    false_positive_patterns = [
        r'customer support|help desk|faq|how to',
        r'price|cost|pricing|quote',
        r'status|update|progress'
    ]
    blocked_benign = 0
    for log in agent_logs:
        if log.get('llama_guard_blocked') and log.get('safety_category'):
            content = log.get('input_content', '')
            if any(re.search(pattern, content, re.IGNORECASE) for pattern in false_positive_patterns):
                blocked_benign += 1
    false_positive_rate = blocked_benign / len([l for l in agent_logs if l.get('llama_guard_blocked')])
    return {'alert': false_positive_rate > 0.3, 'rate': false_positive_rate}

from pydantic import ValidationError
import json

def detect_tool_schema_drift(tool_response, expected_schema):
    try:
        # Llama Stack tool responses should match registered Pydantic models
        validated = expected_schema.model_validate(tool_response)
        return {'valid': True, 'data': validated}
    except ValidationError as e:
        missing_fields = [err['loc'] for err in e.errors() if err['type'] == 'missing']
        extra_fields = [err['loc'] for err in e.errors() if err['type'] == 'extra_forbidden']
        return {
            'valid': False,
            'drift_type': 'schema_mismatch',
            'missing': missing_fields,
            'extra': extra_fields,
            'error_count': len(e.errors())
        }

