class AdaptiveLlamaAgent(LlamaStackAgent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.progress_threshold = 0.7
        self.max_repeated_tools = 3

    def should_terminate(self, execution_state):
        turns = len(execution_state.turns)
        if turns >= self.max_turns:
            return True

        # Check resolution progress
        if execution_state.get('confidence') > self.progress_threshold:
            return True

        # Detect tool looping
        recent_tools = [t.get('tool_name') for t in execution_state.turns[-5:]]
        if len(set(recent_tools)) == 1 and recent_tools:
            return True

        return False

from functools import wraps
from pydantic import BaseModel

def schema_enforced_tool(tool_func):
    @wraps(tool_func)
    def wrapper(*args, **kwargs):
        raw_result = tool_func(*args, **kwargs)

        # Auto-fix common schema drifts
        if isinstance(raw_result, dict):
            # Ensure required fields exist
            for field in tool_func.__schema__.model_fields:
                if field not in raw_result:
                    raw_result[field] = None

            # Validate and correct
            try:
                return tool_func.__schema__.model_validate(raw_result)
            except:
                # Fallback to string response
                return {'error': 'schema_validation_failed', 'raw': raw_result}

        return raw_result
    wrapper.__schema__ = tool_func.__schema__
    return wrapper

# Usage
@schema_enforced_tool
@llama_stack_tool
class CalculatorResponse(BaseModel):
    result: float
    unit: str = 'none'
